const{SlashCommandBuilder:SlashCommandBuilder,EmbedBuilder:EmbedBuilder,PermissionFlagsBits:PermissionFlagsBits}=require("discord.js"),fs=require("fs"),path=require("path");class IgnoreCommand{constructor(){this.ignoreFilePath=path.join(__dirname,"..","ignored-collections.txt")}getCommandData(){return(new SlashCommandBuilder).setName("ignore").setDescription("Manage ignored NFT collections").addSubcommand((subcommand=>subcommand.setName("add").setDescription("Add collection to ignore list").addStringOption((option=>option.setName("slug").setDescription("Collection slug (e.g. bored-ape-yacht-club)").setRequired(!0))))).addSubcommand((subcommand=>subcommand.setName("remove").setDescription("Remove collection from ignore list").addStringOption((option=>option.setName("slug").setDescription("Collection slug to remove").setRequired(!0))))).addSubcommand((subcommand=>subcommand.setName("list").setDescription("Show all ignored collections"))).addSubcommand((subcommand=>subcommand.setName("clear").setDescription("Remove all ignored collections"))).setDefaultMemberPermissions(PermissionFlagsBits.Administrator)}async execute(interaction){const subcommand=interaction.options.getSubcommand();console.log(`🚫 Ignore command executed - subcommand: ${subcommand}, user: ${interaction.user.username}`),await interaction.deferReply({ephemeral:!0});try{switch(subcommand){case"add":await this.handleAdd(interaction);break;case"remove":await this.handleRemove(interaction);break;case"list":await this.handleList(interaction);break;case"clear":await this.handleClear(interaction);break;default:await interaction.editReply({content:"❌ Unknown subcommand.",embeds:[]})}}catch(error){console.error("❌ Error in ignore command:",error),await interaction.editReply({content:`❌ Command failed: ${error.message}`,embeds:[]})}}async handleAdd(interaction){const slug=interaction.options.getString("slug").toLowerCase().trim();if(!slug||slug.includes(" ")||slug.includes("#"))return void await interaction.editReply({content:"❌ Invalid collection slug format. Use the slug from OpenSea URL.\nExample: `bored-ape-yacht-club`",embeds:[]});const ignoredCollections=this.readIgnoredCollections();if(ignoredCollections.includes(slug))return void await interaction.editReply({content:`⚠️ Collection \`${slug}\` is already in the ignore list.`,embeds:[]});ignoredCollections.push(slug),this.writeIgnoredCollections(ignoredCollections),this.reloadConfig();const embed=(new EmbedBuilder).setTitle("🚫 Collection Added to Ignore List").setDescription(`Successfully added **${slug}** to the ignore list.`).setColor(16739179).addFields({name:"📊 Collection",value:`\`${slug}\``,inline:!0},{name:"📝 Total Ignored",value:`${ignoredCollections.length} collection${1!==ignoredCollections.length?"s":""}`,inline:!0},{name:"⚠️ Note",value:"Transactions from this collection will no longer send Discord notifications.",inline:!1},{name:"🔗 OpenSea",value:`[View Collection](https://opensea.io/collection/${slug})`,inline:!1}).setTimestamp().setFooter({text:"Skadi NFT Tracker"});await interaction.editReply({content:"",embeds:[embed]}),console.log(`✅ Added ${slug} to ignore list (total: ${ignoredCollections.length})`)}async handleRemove(interaction){const slug=interaction.options.getString("slug").toLowerCase().trim(),ignoredCollections=this.readIgnoredCollections();if(!ignoredCollections.includes(slug))return void await interaction.editReply({content:`⚠️ Collection \`${slug}\` is not in the ignore list.\nUse \`/ignore list\` to see all ignored collections.`,embeds:[]});const filteredCollections=ignoredCollections.filter((s=>s!==slug));this.writeIgnoredCollections(filteredCollections),this.reloadConfig();const embed=(new EmbedBuilder).setTitle("✅ Collection Removed from Ignore List").setDescription(`Successfully removed **${slug}** from the ignore list.`).setColor(5361510).addFields({name:"📊 Collection",value:`\`${slug}\``,inline:!0},{name:"📝 Total Ignored",value:`${filteredCollections.length} collection${1!==filteredCollections.length?"s":""}`,inline:!0},{name:"✅ Note",value:"Transactions from this collection will now send Discord notifications.",inline:!1},{name:"🔗 OpenSea",value:`[View Collection](https://opensea.io/collection/${slug})`,inline:!1}).setTimestamp().setFooter({text:"Skadi NFT Tracker"});await interaction.editReply({content:"",embeds:[embed]}),console.log(`✅ Removed ${slug} from ignore list (total: ${filteredCollections.length})`)}async handleList(interaction){const ignoredCollections=this.readIgnoredCollections();if(0===ignoredCollections.length)return void await interaction.editReply({content:"📋 **Ignored Collections**\n\n✅ No collections are currently being ignored.\n\n💡 Use `/ignore add slug:collection-name` to add a collection to the ignore list.",embeds:[]});const embed=(new EmbedBuilder).setTitle("🚫 Ignored Collections").setDescription(`Currently ignoring **${ignoredCollections.length}** collection${1!==ignoredCollections.length?"s":""}`).setColor(16739179).setTimestamp().setFooter({text:"Skadi NFT Tracker"});for(let i=0;i<ignoredCollections.length;i+=10){const collectionsList=ignoredCollections.slice(i,i+10).map(((slug,index)=>`${i+index+1}. [\`${slug}\`](https://opensea.io/collection/${slug})`)).join("\n"),fieldName=0===i?"📋 Collections":"📋 Collections (cont.)";embed.addFields({name:fieldName,value:collectionsList.length>1024?collectionsList.substring(0,1020)+"...":collectionsList,inline:!1})}embed.addFields({name:"⚙️ Management",value:"• Use `/ignore remove slug:NAME` to remove a collection\n• Use `/ignore clear` to remove all collections",inline:!1}),await interaction.editReply({content:"",embeds:[embed]})}async handleClear(interaction){const ignoredCollections=this.readIgnoredCollections();if(0===ignoredCollections.length)return void await interaction.editReply({content:"⚠️ The ignore list is already empty.",embeds:[]});const count=ignoredCollections.length;this.writeIgnoredCollections([]),this.reloadConfig();const embed=(new EmbedBuilder).setTitle("🗑️ Ignore List Cleared").setDescription(`Successfully removed **${count}** collection${1!==count?"s":""} from the ignore list.`).setColor(16755021).addFields({name:"✅ Status",value:"All collections cleared",inline:!0},{name:"📝 Total Ignored",value:"0 collections",inline:!0},{name:"⚠️ Note",value:"All collections will now send Discord notifications.",inline:!1}).setTimestamp().setFooter({text:"Skadi NFT Tracker"});await interaction.editReply({content:"",embeds:[embed]}),console.log(`✅ Cleared ignore list (removed ${count} collections)`)}readIgnoredCollections(){try{if(!fs.existsSync(this.ignoreFilePath))return[];return fs.readFileSync(this.ignoreFilePath,"utf-8").split("\n").map((line=>line.trim())).filter((line=>line.length>0&&!line.startsWith("#"))).map((slug=>slug.toLowerCase()))}catch(error){return console.error("❌ Error reading ignored collections:",error.message),[]}}writeIgnoredCollections(collections){try{const content=["# 🚫 Ignored NFT Collections","# Add collection slugs here (one per line)","# Lines starting with # are comments and will be ignored","#","# How to find collection slug:","# - Go to OpenSea: https://opensea.io/collection/SLUG","# - The slug is the last part of the URL","#","# Managed via Discord /ignore command",""].join("\n")+collections.join("\n")+(collections.length>0?"\n":"");fs.writeFileSync(this.ignoreFilePath,content,"utf-8")}catch(error){throw console.error("❌ Error writing ignored collections:",error.message),error}}reloadConfig(){try{const configPath=path.join(__dirname,"..","config.js");delete require.cache[require.resolve(configPath)];const config=require("../config");console.log("🔄 Config reloaded with updated ignore list"),console.log("📋 Current ignored collections:",config.ignoredCollections)}catch(error){console.error("❌ Error reloading config:",error.message)}}}module.exports=IgnoreCommand;